jQuery(function($){let otpVerified=!1;function showError(target,message){target.siblings('.error-message').remove();target.after(`<span class="error-message" style="color:red; font-size:13px;">${message}</span>`)}
function clearError(target){target.siblings('.error-message').remove()}
$('input[name="role"]').on('change',function(){if($(this).val()==='seller'){$('#send-otp-btn').show().text('Send OTP')}else{$('#send-otp-btn, #otp-section').hide();otpVerified=!1;$('#otp_verified').val('0')}});$('#send-otp-btn').on('click',function(){const phoneField=$('#shop-phone');const codeField=$('#country_code');const phone=phoneField.val().trim();const countryCode=codeField.val().trim();clearError(phoneField);clearError(codeField);if(!countryCode){showError(codeField,'Country code is required');return}
if(!phone){showError(phoneField,'Phone number is required');return}
$.post(bragsy_otp_ajax.ajax_url,{action:'bragsy_send_seller_otp',phone:phone,country_code:countryCode,nonce:bragsy_otp_ajax.nonce},function(res){if(res.success){$('#otp-section').show();$('#send-otp-btn').text('Send Again');$('#otp-message').text('OTP sent! Please check your phone.').css('color','green')}else{$('#otp-message').text(res.data).css('color','red')}})});$('#verify-otp-btn').on('click',function(){const otpInput=$('#otp-input');const otp=otpInput.val().trim();clearError(otpInput);if(!otp){showError(otpInput,'Please enter the OTP');return}
$.post(bragsy_otp_ajax.ajax_url,{action:'bragsy_verify_seller_otp',otp:otp,nonce:bragsy_otp_ajax.nonce},function(res){if(res.success){otpVerified=!0;$('#otp-message').text('OTP verified!').css('color','green');$('#otp_verified').val('1');$('#otp-section').hide();$('#send-otp-btn').hide()}else{$('#otp-message').text(res.data).css('color','red');$('#otp_verified').val('0')}})});$('form.register').on('submit',function(e){const isSeller=$('input[name="role"]:checked').val()==='seller';if(isSeller&&$('#otp_verified').val()!=='1'){e.preventDefault();showError($('#shop-phone'),'Please verify your phone number');$('#shop-phone').focus()}else if(isSeller&&$('#passport_upload_individual').val()==''){e.preventDefault();showError($('#upload_passport_button_individual'),'Please upload your Passport');$('#account_type').focus()}})})